#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>

typedef struct Edge {int to; long long w; struct Edge* next;} Edge;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        Edge** adj = (Edge**)calloc(N+1, sizeof(Edge*));
        for(int i=0;i<M;i++){
            int u,v; long long w; scanf("%d %d %lld", &u, &v, &w);
            Edge* e1 = (Edge*)malloc(sizeof(Edge)); e1->to=v; e1->w=w; e1->next=adj[u]; adj[u]=e1;
            Edge* e2 = (Edge*)malloc(sizeof(Edge)); e2->to=u; e2->w=w; e2->next=adj[v]; adj[v]=e2;
        }
        const long long INF = 9e18;
        long long* dist = (long long*)malloc((N+1)*sizeof(long long));
        bool* vis = (bool*)calloc(N+1, sizeof(bool));
        for(int i=1;i<=N;i++) dist[i]=INF;
        dist[1]=0;
        for(int iter=0; iter<N; ++iter){
            int v=-1; long long best=INF;
            for(int i=1;i<=N;i++) if(!vis[i] && dist[i]<best){best=dist[i]; v=i;}
            if(v==-1) break;
            vis[v]=true;
            for(Edge* e=adj[v]; e; e=e->next){
                if(dist[e->to] > dist[v] + e->w){
                    dist[e->to] = dist[v] + e->w;
                }
            }
        }
        for(int i=1;i<=N;i++){
            if(dist[i]==INF) printf("-1");
            else printf("%lld", dist[i]);
            if(i<N) printf(" ");
        }
        printf("\n");
        // free memory
        for(int i=1;i<=N;i++){
            Edge* e=adj[i];
            while(e){ Edge* nxt=e->next; free(e); e=nxt; }
        }
        free(adj); free(dist); free(vis);
    }
    return 0;
}

