import java.io.*;
import java.util.*;
public class Main {
    static class Edge{int to; long w; Edge(int t,long w){this.to=t;this.w=w;}}
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            List<Edge>[] adj = new ArrayList[N+1];
            for(int i=1;i<=N;i++) adj[i]=new ArrayList<>();
            for(int i=0;i<M;i++){
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                long w = Long.parseLong(st.nextToken());
                adj[u].add(new Edge(v,w));
                adj[v].add(new Edge(u,w));
            }
            final long INF = Long.MAX_VALUE/4;
            long[] dist = new long[N+1];
            Arrays.fill(dist, INF);
            boolean[] vis = new boolean[N+1];
            PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a->a[0]));
            dist[1]=0; pq.add(new long[]{0,1});
            while(!pq.isEmpty()){
                long[] cur = pq.poll();
                long d = cur[0]; int v = (int)cur[1];
                if(vis[v]) continue; vis[v]=true;
                for(Edge e: adj[v]){
                    if(dist[e.to] > d + e.w){
                        dist[e.to] = d + e.w;
                        pq.add(new long[]{dist[e.to], e.to});
                    }
                }
            }
            for(int i=1;i<=N;i++){
                if(dist[i]==INF) out.append(-1);
                else out.append(dist[i]);
                if(i<N) out.append(' ');
            }
            if(T>0) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

