import sys
import heapq

def solve_one():
    data = sys.stdin.readline().split()
    while len(data)==0:
        data = sys.stdin.readline().split()
    N, M = map(int, data)
    adj = [[] for _ in range(N+1)]
    for _ in range(M):
        u, v, w = map(int, sys.stdin.readline().split())
        adj[u].append((v, w))
        adj[v].append((u, w))
    INF = 10**19
    dist = [INF]*(N+1)
    dist[1] = 0
    pq = [(0,1)]
    visited = [False]*(N+1)
    while pq:
        d, v = heapq.heappop(pq)
        if visited[v]:
            continue
        visited[v] = True
        for to, w in adj[v]:
            nd = d + w
            if nd < dist[to]:
                dist[to] = nd
                heapq.heappush(pq, (nd, to))
    return ' '.join(str(-1 if dist[i]==INF else dist[i]) for i in range(1, N+1))

def main():
    T_line = sys.stdin.readline()
    while T_line.strip() == '':
        T_line = sys.stdin.readline()
    T = int(T_line)
    outputs = []
    for _ in range(T):
        outputs.append(solve_one())
    sys.stdout.write('\n'.join(outputs))

if __name__ == "__main__":
    main()

