let idx = 0;
const T = input[idx++];
let outputs = [];
for(let t=0; t<T; t++){
  const N = input[idx++];
  const M = input[idx++];
  const adj = Array.from({length: N+1}, ()=>[]);
  for(let i=0;i<M;i++){
    const u = input[idx++];
    const v = input[idx++];
    const w = input[idx++];
    adj[u].push([v,w]);
    adj[v].push([u,w]);
  }
  const INF = 9e18;
  const dist = new Array(N+1).fill(INF);
  const visited = new Array(N+1).fill(false);
  dist[1]=0;
  // simple O(N^2) Dijkstra (N<=1000)
  for(let i=1;i<=N;i++){
    let v = -1;
    let best = INF;
    for(let j=1;j<=N;j++) if(!visited[j] && dist[j] < best){best = dist[j]; v=j;}
    if(v===-1) break;
    visited[v]=true;
    for(const [to,w] of adj[v]){
      if(dist[to] > dist[v] + w){
        dist[to] = dist[v] + w;
      }
    }
  }
  let line = '';
  for(let i=1;i<=N;i++){
    line += (dist[i]===INF ? -1 : dist[i]);
    if(i<N) line += ' ';
  }
  outputs.push(line);
}
